class Solution:
    def robotWithString(self, s):
        """
        :type s: str
        :rtype: str
        """
        # Min char from each position onwards
        min_char = [''] * len(s)
        min_char[-1] = s[-1]
        for i in range(len(s) - 2, -1, -1):
            min_char[i] = min(s[i], min_char[i + 1])

        stack = []
        result = []

        for i in range(len(s)):
            stack.append(s[i])

            # While top of stack is smallest remaining, pop to result
            while stack and stack[-1] == min_char[i] if i < len(s) else False:
                result.append(stack.pop())

            if i + 1 < len(s):
                while stack and stack[-1] <= min_char[i + 1]:
                    result.append(stack.pop())

        while stack:
            result.append(stack.pop())

        return ''.join(result)
